export const checkMarkerFitCentered = (
  x: number,
  markerWidth: number,
  trackLeftBoundary: number,
  trackRightBoundary: number,
) => {
  const candidateHalfMarker = markerWidth / 2;

  const candidateMarkerX0 = x - candidateHalfMarker;

  const overflowsLeft = candidateMarkerX0 < trackLeftBoundary;
  const overflowsRight = candidateMarkerX0 + markerWidth >= trackRightBoundary;

  return !overflowsLeft && !overflowsRight;
};
